VALUES
('bookkeeper-moex-01202', 'bookkeeper', 'bookkeeper-moex-105-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '公司應收之股款，股東並未實際繳納，而以申請文件表明收足，或股東雖已繳納而於登記後將股款發還 股東，或任由股東收回者，為資本不實，公司法對此設有相關之規範，惟不包括下列何者？', '["對於公司負責人可處刑責", "公司負責人應與各該股東連帶賠償公司或第三人因此所受之損害", "資本不實之裁判確定後，由檢察機關通知中央主管機關撤銷或廢止其登記", "於資本不實之裁判確定後、撤銷或廢止登記前已為補正者，主管機關不得撤銷或廢止其登記"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "bd3eaadefb1c", "answer_pdf_sha1": "9b2da7a32888", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01203', 'bookkeeper', 'bookkeeper-moex-105-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', 'A股份有限公司（下稱A公司）設立後選任甲為總經理，惟未向主管機關辦理登記，後甲因違反競業禁 止而遭董事會撤換，改選為乙，向主管機關登記時卻登記為甲。請問下列敘述何者正確？', '["甲雖經A公司選任，惟未經登記，無法取得適法之總經理資格", "經理人選任後雖須登記，惟登記僅為對抗效力，甲於選任後雖未辦理登記，惟仍無礙其取得總經理之資格", "總經理之改選屬於股東會之權限，不得由董事會將之撤換", "A公司雖將總經理改選為乙，然登記為甲，登記之效力優先，甲仍為A公司合法之總經理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "bd3eaadefb1c", "answer_pdf_sha1": "9b2da7a32888", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01204', 'bookkeeper', 'bookkeeper-moex-105-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依公司法規定，公司每屆會計年度終了，應將下列何文件提請股東同意或股東常會承認？①營業報告書', '["財務報表", "主要財產之財產目錄", "盈餘分派或虧損撥補之議案", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "bd3eaadefb1c", "answer_pdf_sha1": "9b2da7a32888", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 43, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01205', 'bookkeeper', 'bookkeeper-moex-105-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '公司之下列登記事項，何者目前仍無法在主管機關之資訊網站查閱？', '["所營事業", "董事、監察人姓名及持股", "公司章程", "資本總額或實收資本額"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "bd3eaadefb1c", "answer_pdf_sha1": "9b2da7a32888", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01206', 'bookkeeper', 'bookkeeper-moex-105-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依據記帳士職業倫理道德規範，共列舉數項記帳士應遵守之行為準則，下列何者非屬之？', '["廉潔", "務實", "保密", "適任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "bd3eaadefb1c", "answer_pdf_sha1": "9b2da7a32888", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL)
